// ---------- 인덱스 (모듈 스코프 1회) ----------
const BY_SLUG = new Map();
const GROUPS  = new Map();   // "시도|시군구" -> [region...]
const SIDOS   = [];          // 시도 순서
const SIDO_SET= new Set();
const SLUG2SIDO = new Map();         // 시도슬러그 -> 시도명
const SLUG2GUNGU = new Map();        // 시군구슬러그 -> {sido,gungu,key}
const SIDO_GUNGUS = new Map();       // 시도명 -> [시군구명...]
for (const r of REGIONS) {
  BY_SLUG.set(r.s, r);
  const t = r.n.split(" ");
  const sido = t[0];
  const dong = t[t.length - 1];
  const gungu = t.slice(1, -1).join(" ");
  const gk = sido + "|" + gungu;
  r._sido = sido; r._dong = dong; r._gungu = gungu; r._syn = hash(r.s);
  r._sidoSlug = SIDO_SLUGS[sido] || "";
  r._gunguSlug = gungu ? (GUNGU_SLUGS[gk] || "") : "";
  if (!GROUPS.has(gk)) GROUPS.set(gk, []);
  GROUPS.get(gk).push(r);
  if (!SIDO_SET.has(sido)) { SIDO_SET.add(sido); SIDOS.push(sido); SIDO_GUNGUS.set(sido, []); }
  if (r._sidoSlug && !SLUG2SIDO.has(r._sidoSlug)) SLUG2SIDO.set(r._sidoSlug, sido);
  if (r._gunguSlug && !SLUG2GUNGU.has(r._gunguSlug)) SLUG2GUNGU.set(r._gunguSlug, {sido:sido, gungu:gungu, key:gk});
  if (gungu) { const arr=SIDO_GUNGUS.get(sido); if (arr.indexOf(gungu)<0) arr.push(gungu); }
}

