function applySyn(s,seed){
  for(let i=0;i<SYN.length;i++){
    const g=SYN[i], rep=g[1][(seed+i*13)%g[1].length];
    if(rep!==g[0]) s=s.split(g[0]).join(rep);
  }
  return s;
}
function fill(s,R){ s=s.replace(/\{F\}/g,R.n).replace(/\{S\}/g,R._sido).replace(/\{G\}/g,R._gungu||R._sido).replace(/\{D\}/g,R._dong); return applySyn(s,R._syn); }

const DAY=86400000, PERIOD=18;
function pad(n){ return n<10?"0"+n:""+n; }
function isoDate(d){ return d.getFullYear()+"-"+pad(d.getMonth()+1)+"-"+pad(d.getDate()); }
function korDate(d){ return d.getFullYear()+"년 "+(d.getMonth()+1)+"월 "+d.getDate()+"일"; }
function publishedDate(seed){ return new Date(Date.parse("2025-09-01") + (seed%160)*DAY); }
function modifiedDate(seed){
  const off = seed % PERIOD;                       // 지역마다 갱신일 분산
  const periods = Math.floor((Date.now()/DAY - off)/PERIOD);
  return new Date((periods*PERIOD + off)*DAY);     // 최근 18일 이내, 18일마다 갱신
}

